function Navigation() {
  return (
    <div
      style={{
        position: "relative",
        width: "100%",
        height: "208px",
        background: "black",
      }}
    >
      {/* Name */}
      <div
        style={{
          position: "absolute",
          left: "99px",
          top: "calc(50% - 24px)",
          color: "white",
          fontSize: "40px",
          fontFamily: "Inter, sans-serif",
          fontWeight: "400",
        }}
      >
        Therese Wong
      </div>

      {/* Navigation Links */}
      <div
        style={{
          position: "absolute",
          left: "823px",
          top: "86.07px",
          display: "flex",
          gap: "7.471px",
          alignItems: "center",
          color: "white",
          fontSize: "29.884px",
          fontFamily: "Inter, sans-serif",
          fontWeight: "400",
        }}
      >
        <span style={{ cursor: "pointer" }}>projects</span>
        <span style={{ cursor: "pointer" }}>about</span>
        <span style={{ cursor: "pointer" }}>linkedin</span>
        <span style={{ cursor: "pointer" }}>resume</span>
        <span style={{ cursor: "pointer" }}>email</span>
      </div>

      {/* Divider Line */}
      <div
        style={{
          position: "absolute",
          top: "calc(50% + 104px)",
          left: "102.5px",
          width: "1235px",
          height: "1px",
          background: "white",
        }}
      />
    </div>
  );
}

export default Navigation;
